concept.codeExample:
/* Before: slow sequential scan */
EXPLAIN ANALYZE SELECT id FROM orders WHERE user_id = 42 AND status = 'paid';

/* After: composite covering index */
CREATE INDEX idx_orders_user_status_created ON orders(user_id, status, created_at);
EXPLAIN ANALYZE SELECT id, created_at FROM orders WHERE user_id = 42 AND status = 'paid' ORDER BY created_at DESC LIMIT 10;
